# Tests – Happy-path: successful publish
# ---------------------------------------------------------------------------

class TestSuccessfulPublish:

    def test_returns_announcement_object(self, service, system_admin, valid_request):
        result = service.publish(system_admin, valid_request)
        assert isinstance(result, Announcement)

    def test_announcement_is_marked_published(self, service, system_admin, valid_request):
        result = service.publish(system_admin, valid_request)
        assert result.published is True

    def test_announcement_title_matches_request(self, service, system_admin, valid_request):
        result = service.publish(system_admin, valid_request)
        assert result.title == valid_request.title

    def test_announcement_body_matches_request(self, service, system_admin, valid_request):
        result = service.publish(system_admin, valid_request)
        assert result.body == valid_request.body

    def test_announcement_contains_all_requested_departments(
        self, service, system_admin, valid_request
    ):
        result = service.publish(system_admin, valid_request)
        assert set(result.department_ids) == set(valid_request.department_ids)

    def test_announcement_author_is_acting_admin(self, service, system_admin, valid_request):
        result = service.publish(system_admin, valid_request)
        assert result.author_id == system_admin.id

    def test_announcement_persisted_to_repository(
        self, service, system_admin, valid_request, announcement_repo
    ):
        service.publish(system_admin, valid_request)
        announcement_repo.save.assert_called_once()

    def test_publish_with_single_department_succeeds(
        self, service, system_admin, single_department_request
    ):
        result = service.publish(system_admin, single_department_request)
        assert result.published is True
        assert result.department_ids == ["dept-eng"]

    def test_publish_to_many_departments_stores_all(
        self, service, system_admin, announcement_repo
    ):
        many_dept_request = PublishRequest(
            title="Company-wide",
            body="All departments message.",
            department_ids=["dept-eng", "dept-hr", "dept-finance", "dept-legal"],
        )
        result = service.publish(system_admin, many_dept_request)
        assert len(result.department_ids) == 4


