class TestWebhookEmission:

    def test_webhook_emitted_exactly_once_on_successful_publish(
        self, service, system_admin, valid_request, webhook_client
    ):
        service.publish(system_admin, valid_request)
        webhook_client.emit.assert_called_once()

    def test_webhook_event_type_is_correct(
        self, service, system_admin, valid_request, webhook_client
    ):
        service.publish(system_admin, valid_request)
        call_kwargs = webhook_client.emit.call_args
        event_type = call_kwargs.kwargs.get("event_type") or call_kwargs.args[0]
        assert event_type == AnnouncementService.WEBHOOK_EVENT_TYPE

    def test_webhook_payload_contains_announcement_id(
        self, service, system_admin, valid_request, webhook_client
    ):
        result = service.publish(system_admin, valid_request)
        payload = webhook_client.emit.call_args.kwargs["payload"]
        assert payload["announcement_id"] == result.id

    def test_webhook_payload_contains_title(
        self, service, system_admin, valid_request, webhook_client
    ):
        service.publish(system_admin, valid_request)
        payload = webhook_client.emit.call_args.kwargs["payload"]
        assert payload["title"] == valid_request.title

    def test_webhook_payload_contains_department_ids(
        self, service, system_admin, valid_request, webhook_client
    ):
        service.publish(system_admin, valid_request)
        payload = webhook_client.emit.call_args.kwargs["payload"]
        assert set(payload["department_ids"]) == set(valid_request.department_ids)

    def test_webhook_payload_contains_author_id(
        self, service, system_admin, valid_request, webhook_client
    ):
        service.publish(system_admin, valid_request)
        payload = webhook_client.emit.call_args.kwargs["payload"]
        assert payload["author_id"] == system_admin.id

    def test_webhook_not_emitted_when_no_departments_selected(
        self, service, system_admin, no_department_request, webhook_client
    ):
        with pytest.raises(NoDepartmentsSelectedError):
            service.publish(system_admin, no_department_request)
        webhook_client.emit.assert_not_called()

    def test_webhook_not_emitted_when_actor_lacks_permission(
        self, service, employee, valid_request, webhook_client
    ):
        with pytest.raises(PermissionDeniedError):
            service.publish(employee, valid_request)
        webhook_client.emit.assert_not_called()

    def test_webhook_not_emitted_when_department_not_found(
        self, service, system_admin, valid_request, webhook_client, department_repo
    ):
        department_repo.exists.return_value = False
        with pytest.raises(DepartmentNotFoundError):
            service.publish(system_admin, valid_request)
        webhook_client.emit.assert_not_called()

    def test_two_separate_publishes_emit_two_webhook_events(
        self, service, system_admin, valid_request, webhook_client
    ):
        service.publish(system_admin, valid_request)
        service.publish(system_admin, valid_request)
        assert webhook_client.emit.call_count == 2


