class TestDepartmentSelectionValidation:

    def test_empty_department_list_raises_no_departments_selected_error(
        self, service, system_admin, no_department_request
    ):
        with pytest.raises(NoDepartmentsSelectedError):
            service.publish(system_admin, no_department_request)

    def test_error_message_mentions_department_selection(
        self, service, system_admin, no_department_request
    ):
        with pytest.raises(NoDepartmentsSelectedError, match="department"):
            service.publish(system_admin, no_department_request)

    def test_none_department_list_raises_no_departments_selected_error(
        self, service, system_admin
    ):
        request = PublishRequest(title="Test", body="Body", department_ids=None)
        with pytest.raises((NoDepartmentsSelectedError, TypeError)):
            service.publish(system_admin, request)

    def test_unknown_department_id_raises_department_not_found_error(
        self, service, system_admin, department_repo
    ):
        department_repo.exists.side_effect = lambda dept_id: dept_id != "dept-unknown"
        request = PublishRequest(
            title="Test",
            body="Body",
            department_ids=["dept-eng", "dept-unknown"],
        )
        with pytest.raises(DepartmentNotFoundError, match="dept-unknown"):
            service.publish(system_admin, request)

    def test_all_unknown_departments_raise_department_not_found_error(
        self, service, system_admin, department_repo
    ):
        department_repo.exists.return_value = False
        request = PublishRequest(
            title="Test",
            body="Body",
            department_ids=["dept-ghost"],
        )
        with pytest.raises(DepartmentNotFoundError):
            service.publish(system_admin, request)

    def test_announcement_not_persisted_when_no_departments_selected(
        self, service, system_admin, no_department_request, announcement_repo
    ):
        with pytest.raises(NoDepartmentsSelectedError):
            service.publish(system_admin, no_department_request)
        announcement_repo.save.assert_not_called()

    def test_announcement_not_persisted_when_department_not_found(
        self, service, system_admin, valid_request, announcement_repo, department_repo
    ):
        department_repo.exists.return_value = False
        with pytest.raises(DepartmentNotFoundError):
            service.publish(system_admin, valid_request)
        announcement_repo.save.assert_not_called()


