class TestAuthorisation:

    def test_system_admin_can_publish(self, service, system_admin, valid_request):
        result = service.publish(system_admin, valid_request)
        assert result.published is True

    def test_org_admin_cannot_publish(self, service, org_admin, valid_request):
        with pytest.raises(PermissionDeniedError):
