class TestEdgeCases:

    def test_duplicate_department_ids_are_accepted(
        self, service, system_admin, department_repo
    ):
        """Deduplication (if any) is the service's concern, not rejection."""
        request = PublishRequest(
            title="Dup dept test",
            body="Body",
            department_ids=["dept-eng", "dept-eng"],
        )
        # Should not raise; behaviour (dedup or keep) is implementation detail
        result = service.publish(system_admin, request)
        assert result.published is True

    def test_whitespace_only_title_is_passed_through(
        self, service, system_admin, valid_request
    ):
        """Content validation is out-of-scope for this requirement; service must not crash."""
        valid_request.title = "   "
        result = service.publish(system_admin, valid_request)
        assert isinstance(result, Announcement)

    def test_very_long_body_does_not_cause_error(self, service, system_admin, valid_request):
        valid_request.body = "x" * 100_000
        result = service.publish(system_admin, valid_request)
        assert result.published is True

    def test_webhook_failure_propagates_to_caller(
        self, service, system_admin, valid_request, webhook_client
    ):
        """If the webhook client raises, the caller must be notified."""
        webhook_client.emit.side_effect = ConnectionError("Webhook endpoint unreachable")
        with pytest.raises(ConnectionError, match="Webhook endpoint unreachable"):
            service.publish(system_admin, valid_request)

    def test_repo_failure_does_not_emit_webhook(
        self, service, system_admin, valid_request, announcement_repo, webhook_client
    ):
        announcement_repo.save.side_effect = RuntimeError("DB write failed")
        with pytest.raises(RuntimeError, match="DB write failed"):
            service.publish(system_admin, valid_request)
        webhook_client.emit.assert_not_called()

